import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

const Electronics = () => {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchPosts = async () => {
      try {
        // FIXED: Port 5001 use kiya hai kyunki admin wahin se bhej raha hai
        // FIXED: Category 'Electronics' (Capital E) rakha hai as per Admin
        const res = await axios.get('http://localhost:5001/api/blog/Electronics');
        setPosts(res.data);
      } catch (err) {
        console.error("Error fetching electronics posts:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchPosts();
  }, []);

  return (
    <div className="bg-white antialiased w-full min-h-screen">

      {/* 1. HEADER SECTION */}
      <section className="pt-32 pb-20 px-6 md:px-16 w-full bg-gradient-to-br from-[#0f172a] to-[#1e293b] text-white">
        <div className="max-w-7xl mx-auto">
          <span className="text-orange-500 font-black text-xs uppercase tracking-[0.3em] mb-4 block">Industry Sector</span>
          <h1 className="text-6xl md:text-8xl font-black tracking-tighter mb-6 leading-[0.9]">
           Electronics <br /><span className="text-orange-500 italic">Solutions</span>
          </h1>
          <p className="text-slate-400 text-lg md:text-xl font-medium max-w-2xl leading-relaxed">
            Advancing the future of electronics through precision engineering and global expertise.
          </p>
        </div>
      </section>

      {/* 2. DYNAMIC BLOG POSTS SECTION */}
      <section className="w-full bg-white">
        <div className="max-w-7xl mx-auto">
          {loading ? (
            <div className="py-40 text-center">
              <div className="inline-block w-12 h-12 border-4 border-orange-500 border-t-transparent rounded-full animate-spin mb-4"></div>
              <p className="text-gray-400 font-bold uppercase tracking-widest text-sm">Syncing Data...</p>
            </div>
          ) : posts.length > 0 ? (
            <div className="divide-y divide-gray-100">
              {posts.map((post) => (
                <div 
                  key={post._id} 
                  className="px-6 py-20 flex flex-col md:flex-row items-start gap-16 group hover:bg-gray-50/50 transition-all duration-700"
                >
                  {/* Left: Image Container */}
                  <div className="w-full md:w-1/3 flex-shrink-0">
                    <div className="aspect-square bg-gray-100 rounded-[3rem] overflow-hidden relative shadow-2xl group-hover:rounded-[1.5rem] transition-all duration-700">
                      {post.image ? (
                        <img 
                          src={`http://localhost:5001${post.image}`} // URL Prefix added
                          alt={post.title} 
                          className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000"
                        />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center text-8xl grayscale opacity-20">⚡</div>
                      )}
                      <div className="absolute inset-0 ring-1 ring-inset ring-black/10 rounded-[3rem] group-hover:rounded-[1.5rem] transition-all"></div>
                    </div>
                  </div>

                  {/* Right: Content Container */}
                  <div className="w-full md:w-2/3 pt-4">
                    <div className="flex items-center gap-4 mb-6">
                      <span className="px-4 py-1 bg-orange-100 text-orange-600 rounded-full text-[10px] font-black uppercase tracking-widest">
                        Industrial Update
                      </span>
                      <span className="text-gray-300 text-sm font-medium">
                        {new Date(post.createdAt).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' })}
                      </span>
                    </div>

                    <h3 className="text-4xl md:text-5xl font-black text-gray-900 mb-6 tracking-tighter leading-tight group-hover:text-orange-600 transition-colors">
                      {post.title}
                    </h3>

                    <p className="text-gray-500 text-xl leading-relaxed mb-10 font-medium line-clamp-4">
                      {post.description}
                    </p>

                    <button className="flex items-center gap-4 text-gray-950 font-black uppercase text-xs tracking-[0.2em] group/link">
                      Read Full Report 
                      <span className="w-10 h-[2px] bg-gray-200 group-hover/link:w-16 group-hover/link:bg-orange-600 transition-all duration-500"></span>
                    </button>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="py-40 text-center px-6">
              <div className="text-8xl mb-8 opacity-10">📂</div>
              <h3 className="text-2xl font-black text-gray-300 uppercase tracking-widest">No Posts Found</h3>
              <p className="text-gray-400 mt-2">Electronics category mein abhi tak koi post nahi hai.</p>
            </div>
          )}
        </div>
      </section>

      {/* 3. CTA SECTION */}
      <section className="py-32 px-6">
        <div className="max-w-7xl mx-auto">
          <div className="bg-orange-600 rounded-[4rem] p-12 md:p-24 relative overflow-hidden shadow-[0_50px_100px_-20px_rgba(234,88,12,0.3)]">
            <div className="relative z-10 text-center md:text-left flex flex-col md:flex-row items-center justify-between gap-12">
              <div className="md:w-2/3">
                <h2 className="text-5xl md:text-7xl font-black text-white tracking-tighter mb-8 leading-none">
                  Build the future <br /> with Hudson.
                </h2>
                <Link to="/careers">
                  <button className="bg-white text-orange-600 px-12 py-5 rounded-full font-black text-lg hover:bg-gray-900 hover:text-white transition-all transform hover:-translate-y-1">
                    VIEW OPENINGS
                  </button>
                </Link>
              </div>
              <div className="text-orange-400 text-[12rem] font-black opacity-20 select-none">
                HUD
              </div>
            </div>
          </div>
        </div>
      </section>

    </div>
  );
};

export default Electronics;
